# Day 186: Testing: Unit Tests with Pytest — Writing Your First Tests
# test_model.py — Unit Tests with Pytest
import pytest

# Code to test
def predict(features):
    if not features: raise ValueError("Empty features")
    return 1 if sum(features) > 0 else 0

def preprocess(text):
    return text.lower().strip()

# Tests
def test_predict_positive():
    assert predict([1.0, 2.0, 3.0]) == 1

def test_predict_negative():
    assert predict([-1.0, -2.0, -3.0]) == 0

def test_predict_empty_raises():
    with pytest.raises(ValueError):
        predict([])

def test_preprocess():
    assert preprocess("  HELLO  ") == "hello"
    assert preprocess("Test") == "test"

# Run: pytest test_model.py -v
print("Run: pytest test_model.py -v")

# Run tests inline
for test_fn in [test_predict_positive, test_predict_negative, test_preprocess]:
    try:
        test_fn()
        print(f"  ✅ {test_fn.__name__}")
    except AssertionError:
        print(f"  ❌ {test_fn.__name__}")
